  products: INITIAL_PRODUCTS.map(cloneProduct),
  activeSync: null,
  syncRuns: 0,
};

function cloneProduct(product) {
  return { ...product };
}

function delay(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function toAvailability(inventory) {
  if (inventory <= 0) {
    return "Out of stock";
  }

  if (inventory < 10) {
    return "Low stock";
  }

  return "In stock";
}

function applyUpstreamChanges(product, index, syncRuns) {
  const inventoryShift = ((syncRuns + index) % 7) - 3;
  const nextInventory = Math.max(0, product.inventory + inventoryShift * 2);
  const priceDelta = ((syncRuns + index) % 3) * 5 - 5;
  const nextPrice = Math.max(49, product.price + priceDelta);

  return {
    ...product,
    inventory: nextInventory,
    price: nextPrice,
    availability: toAvailability(nextInventory),
  };
}

export async function readProductsFromSource() {
  await delay(100);

  return {
    lastSyncedAt: catalogState.lastSyncedAt,
    products: catalogState.products.map(cloneProduct),
  };
}

export function isProductSyncRunning() {
  return catalogState.activeSync !== null;
}

export function syncProductsFromUpstream() {
  if (catalogState.activeSync) {
    return catalogState.activeSync;
  }

  catalogState.activeSync = (async () => {
    await delay(1500);

    const nextSyncRun = catalogState.syncRuns + 1;

    catalogState.products = catalogState.products.map((product, index) =>
      applyUpstreamChanges(product, index, nextSyncRun),
    );
    catalogState.lastSyncedAt = new Date().toISOString();
    catalogState.syncRuns = nextSyncRun;
  })().finally(() => {
    catalogState.activeSync = null;
  });

  return catalogState.activeSync;
}


